import com.github.javaparser.ast.type.*;
import com.github.javaparser.ast.nodeTypes.NodeWithJavaParser;
import com.github.javaparser.ast.visitor.ModifierVisitor;
import com.github.javaparser.ast.visitor.Visitable;
import java.io.*;
import java.nio.file.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Process all Java files in the target directory
        String targetDir = args.length > 0 ? args[0] : "/workspace/dropwizard-pac4j";
        processDirectory(Paths.get(targetDir));
    }

    private static void processDirectory(Path dir) throws IOException {
        Files.walk(dir)
            .filter(path -> path.toString().endsWith(".java"))
            .forEach(Main::processFile);
    }

    private static void processFile(Path filePath) {
        try {
            String content = Files.readString(filePath);
            CompilationUnit cu = StaticJavaParser.parse(content);

            // Apply transformations to fix Jakarta Servlet API 6.0.0 breaking changes
            JakartaServletFixVisitor visitor = new JakartaServletFixVisitor();
            cu.accept(visitor, null);

            // Write back the modified content
            Files.writeString(filePath, cu.toString());
            System.out.println("Processed: " + filePath);
        } catch (Exception e) {
            System.err.println("Error processing " + filePath + ": " + e.getMessage());
        }
    }

    static class JakartaServletFixVisitor extends ModifierVisitor<Void> {
        @Override
        public Visitable visit(ImportDeclaration importDecl, Void arg) {
            // Fix javax.servlet imports to jakarta.servlet
            if (importDecl.getNameAsString().startsWith("javax.servlet")) {
                String newImport = importDecl.getNameAsString().replace("javax.servlet", "jakarta.servlet");
                importDecl.setName(newImport);
            }
            return super.visit(importDecl, arg);
        }

        @Override
        public Visitable visit(MethodCallExpr methodCall, Void arg) {
            // Fix method calls that use javax.servlet types
            if (methodCall.getNameAsString().equals("addFilter")) {
                // Check if it's calling environment.servlets().addFilter()
                if (methodCall.getScope().isPresent()) {
                    Expression scope = methodCall.getScope().get();
                    if (scope instanceof MethodCallExpr) {
                        MethodCallExpr scopeCall = (MethodCallExpr) scope;
                        if (scopeCall.getNameAsString().equals("servlets")) {
                            // This is environment.servlets().addFilter() - we need to handle this carefully
                            // Actually, this is more complex and likely requires more context
                        }
                    }
                }
            }
            return super.visit(methodCall, arg);
        }
    }
}

